export const meta = {
  name: 'hackathon-idea-and-prompt',
  description: 'Deep-research loop to converge on ONE hackathon idea + the master orchestration prompt for Claude Build Day',
  phases: [
    { title: 'Sweep', detail: '10 parallel research agents, each writes a grounding doc' },
    { title: 'Synthesize', detail: 'merge research, generate candidate ideas' },
    { title: 'Score', detail: 'parallel judges score each idea vs rubric + prohibited list' },
    { title: 'Craft', detail: 'write the master agentic-loop prompt for the winning idea' },
    { title: 'Adversarial', detail: 'critics try to break the idea and the prompt' },
    { title: 'Converge', detail: 'revise and re-check until a critic approves' },
  ],
}

const DIR = '/Users/azaali/CascadeProjects/hackathon/research'

// Shared grounding facts every agent must respect — the real rubric + hard constraints.
const CONTEXT = `
CONTEXT — Claude Build Day (Cerebral Valley + Anthropic), one-day hackathon at Shack15, SF.
Build on Opus 4.8. Solo builder. Hacking 10:30AM-5PM (~6.5h). Deliverable: public GitHub repo, LIVE URL, 1-min demo video, brief + rubric + session log.
SCORING: Impact 35% (real-world potential, fits a problem statement) | Demo 35% (working, impressive, holds up LIVE in 3 min) | Opus 4.8 Use 15% (creative, beyond basic integration, surprising capability) | Orchestration 15% (judged from brief/rubric/workflow scripts: is "done" verifiable by the MODEL without a human — test suite, responding URL, rubric file it grades against — and could another team rerun it tomorrow on a new problem).
STEER: public-data / San Francisco / nonprofit angle (strong Impact narrative; "the tool SF or a nonprofit deserves, built on the public data they already publish").
PROHIBITED (instant DQ): AI Mental Health Advisor; Basic RAG apps; Streamlit apps; Image Analyzers; "AI for Education" chatbot; AI Job Application Screener; AI Nutrition Coach; Personality Analyzers; Medical advice bots; ANY project where a dashboard is the main feature; Sports analyzers/coaches; anything using code/data/assets without rights.
GOAL OF THIS RESEARCH: we are NOT building the product. We are converging on (1) the single best IDEA and (2) the master PROMPT(S) that make Claude spin up sub-agents, set its own goals/rubric, and run a full agentic build->self-correct->iterate->test->verify-done loop with minimal human input.
Use WebSearch and mcp__turbowebfetch__fetch (load via ToolSearch) for live web research. Cite URLs.
`

const FINDINGS_SCHEMA = {
  type: 'object',
  properties: {
    lane: { type: 'string' },
    file_written: { type: 'string', description: 'absolute path of the .md doc you wrote' },
    key_findings: { type: 'array', items: { type: 'string' }, description: '8-15 concrete, specific findings with sources' },
    implications_for_idea: { type: 'array', items: { type: 'string' } },
    implications_for_prompt: { type: 'array', items: { type: 'string' } },
    sources: { type: 'array', items: { type: 'string' } },
  },
  required: ['lane', 'file_written', 'key_findings'],
}

const LANES = [
  { key: 'prior-winners', title: 'Prior Anthropic/CV/Claude hackathon winning repos & patterns',
    task: `Mine GitHub and the web for projects that WON or placed in Anthropic / Cerebral Valley / Claude-Code hackathons and similar agentic-AI hackathons (2024-2026). For each: what it did, why it won, the demo hook, repo link. Extract the PATTERN behind winners (what kinds of ideas win agentic-AI hackathons judged on impact+demo+orchestration). Search GitHub topics, "cerebral valley hackathon winner", "claude hackathon project", Devpost, etc.` },
  { key: 'claude-build-day-repos', title: 'Repos specifically from Claude Build Day / Claude Code dynamic-workflow showcases',
    task: `Find any public repos, demos, or writeups specifically tagged to "Claude Build Day", and the canonical examples in Anthropic's own showcases: claude-quickstarts, claude-cookbooks, anthropics/skills, and the "dynamic workflows in Claude Code" blog. Catalog concrete orchestration scripts/patterns Anthropic itself ships as exemplars. Note what judges will recognize as "creative Opus 4.8 use" vs basic.` },
  { key: 'sf-public-data', title: 'San Francisco public data sources, APIs, datasets',
    task: `Catalog SF / Bay Area public data that an app could build on TODAY: DataSF (data.sfgov.org / Socrata API), SF 311, SFMTA, SF Planning, SF Assessor, Eviction notices, restaurant inspections, permits, crime, budget, campaign finance, public housing, etc. For each promising dataset: what it contains, API access method, freshness, and a real problem it could power. Flag the ones with the strongest "this helps real people / nonprofits" story.` },
  { key: 'nonprofit-gaps', title: 'Nonprofit & civic pain points public-interest tech could solve',
    task: `Research concrete, documented pain points of SF/Bay Area nonprofits and civic orgs that software built on public data could solve in a day: benefits navigation, grant discovery, tenant rights, food access, homelessness services routing, immigrant/language access, FOIA/records, small-org back-office. Find real testimony (blogs, reports, code-for-america, 18F, civic tech writeups). Rank by impact + feasibility-in-6-hours + demo-ability.` },
  { key: 'dynamic-workflows', title: 'Claude Code dynamic workflows & orchestration mechanics',
    task: `Deep-read the "A harness for every task: dynamic workflows in Claude Code" blog and Claude Code docs on workflows, sub-agents, skills, hooks. Extract EXACTLY how to make Claude orchestrate sub-agents, fan out, loop, and self-verify. Capture the concrete syntax/patterns a master prompt would invoke. This grounds how our prompt should be written.` },
  { key: 'opus48-capabilities', title: 'Opus 4.8 distinctive capabilities to showcase',
    task: `Research what makes Opus 4.8 distinctive vs prior models (agentic coding, long-horizon autonomy, tool use, self-correction, 1M context, reasoning). Find what would read to Anthropic judges as "creative use that surprised even us" — beyond a basic API call. Translate into concrete demo moments we could engineer.` },
  { key: 'winning-demo', title: 'What makes a winning 3-minute live demo',
    task: `Research how to win the Demo (35%) + the live 3-min round: what demo structures land, the "wow in 30 seconds" rule, failure modes that kill live demos, how to show "Claude caught and fixed its own failure" (the judges explicitly want this moment). Produce a concrete demo-script template and the single most impressive live moment we should engineer.` },
  { key: 'orchestration-scoring', title: 'Self-verifying "done": rubric files, test suites, responding URLs',
    task: `Research patterns for making "done" verifiable BY THE MODEL without a human (the Orchestration 15% bar): machine-gradable rubric files, test suites the agent runs, a responding deployed URL it curls, eval harnesses, golden outputs. Find concrete examples of rubric.md / eval setups agents grade themselves against. This defines the verification layer our master prompt must include.` },
  { key: 'master-prompt-eng', title: 'Engineering a master prompt for an autonomous agentic build loop',
    task: `Research best practices for ONE master prompt that makes Claude: decompose the problem, spawn sub-agents with roles, set goals + a rubric, build, run tests, deploy, self-correct on failure, and loop until the rubric passes. Find published examples of such "self-driving" build prompts / agent harnesses (Claude best practices, agent SDK, dynamic workflows). Produce a skeleton structure for our master prompt.` },
  { key: 'deploy-fast', title: 'Fastest path solo to a live URL by 5PM + tech stack',
    task: `Research the fastest solo stack to ship a LIVE URL in <6h that an agent can deploy and then CURL to self-verify: Vercel/Next, Cloudflare Workers, Render, Railway, static + serverless. Which deploy targets an agent can drive end-to-end via CLI, get a URL back, and health-check. Recommend ONE default stack optimized for agent-driven deploy + self-verification. Also note data-ingestion speed for SF public APIs.` },
]

// ---------- PHASE 1: SWEEP ----------
phase('Sweep')
log('Round 1: 10 parallel research agents sweeping the problem space')
const sweep = await parallel(LANES.map(lane => () =>
  agent(
    `${CONTEXT}\n\nYOU ARE RESEARCH LANE: "${lane.title}".\nTASK: ${lane.task}\n\nDo thorough live web research (WebSearch + mcp__turbowebfetch__fetch via ToolSearch). Be specific and cite URLs.\nThen WRITE your findings as a markdown doc to ${DIR}/01-${lane.key}.md (use the Write tool, absolute path). Structure: ## Findings (specific, sourced), ## Implications for the IDEA, ## Implications for the PROMPT, ## Sources.\nReturn the structured object.`,
    { label: `sweep:${lane.key}`, phase: 'Sweep', schema: FINDINGS_SCHEMA }
  )
)).then(r => r.filter(Boolean))

log(`Sweep complete: ${sweep.length}/10 lanes returned`)

// ---------- PHASE 2: SYNTHESIZE ----------
phase('Synthesize')
const groundingBlob = sweep.map(s =>
  `### ${s.lane}\nFINDINGS:\n- ${(s.key_findings||[]).join('\n- ')}\nIDEA-IMPLICATIONS:\n- ${(s.implications_for_idea||[]).join('\n- ')}\nPROMPT-IMPLICATIONS:\n- ${(s.implications_for_prompt||[]).join('\n- ')}`
).join('\n\n')

const IDEAS_SCHEMA = {
  type: 'object',
  properties: {
    ideas: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          name: { type: 'string' },
          one_liner: { type: 'string' },
          problem: { type: 'string' },
          who_benefits: { type: 'string' },
          public_data_used: { type: 'string' },
          demo_wow_moment: { type: 'string' },
          why_not_prohibited: { type: 'string' },
          feasible_solo_6h: { type: 'string' },
          opus48_creative_use: { type: 'string' },
        },
        required: ['name', 'one_liner', 'problem', 'demo_wow_moment', 'why_not_prohibited'],
      },
    },
  },
  required: ['ideas'],
}

const synth = await agent(
  `${CONTEXT}\n\nHere is the merged research from 10 lanes:\n${groundingBlob}\n\nFirst, WRITE a synthesis grounding doc to ${DIR}/02-synthesis.md capturing the cross-cutting insights, the winning-pattern, and the design constraints.\nThen generate 5 distinct, strong CANDIDATE IDEAS that (a) use SF/public/nonprofit data, (b) are NOT on the prohibited list (a dashboard cannot be the main feature), (c) are solo-shippable to a live URL in ~6h, (d) have a 30-second "wow" demo moment, (e) showcase creative Opus 4.8 + orchestration. Be concrete about the exact dataset/API each uses. Return the ideas object.`,
  { label: 'synthesize', phase: 'Synthesize', schema: IDEAS_SCHEMA }
)
const candidateIdeas = synth.ideas || []
log(`Generated ${candidateIdeas.length} candidate ideas`)

// ---------- PHASE 3: SCORE (parallel judges, one per idea) ----------
phase('Score')
const SCORE_SCHEMA = {
  type: 'object',
  properties: {
    name: { type: 'string' },
    impact_35: { type: 'number' },
    demo_35: { type: 'number' },
    opus48_15: { type: 'number' },
    orchestration_15: { type: 'number' },
    weighted_total: { type: 'number' },
    prohibited_violation: { type: 'boolean' },
    prohibited_note: { type: 'string' },
    risks: { type: 'array', items: { type: 'string' } },
    verdict: { type: 'string' },
  },
  required: ['name', 'weighted_total', 'prohibited_violation', 'verdict'],
}
const scored = (await parallel(candidateIdeas.map(idea => () =>
  agent(
    `${CONTEXT}\n\nAdversarially SCORE this candidate idea against the EXACT rubric. Be a harsh Anthropic judge.\nIDEA: ${JSON.stringify(idea)}\n\nScore each criterion on its weighted scale (impact /35, demo /35, opus48 /15, orchestration /15), sum to weighted_total /100. CRITICALLY check the prohibited list — if it even resembles a banned category (esp. "dashboard as main feature", "basic RAG"), set prohibited_violation true and explain. List real risks. Give a verdict.`,
    { label: `score:${(idea.name||'idea').slice(0,20)}`, phase: 'Score', schema: SCORE_SCHEMA }
  )
))).filter(Boolean)

const viable = scored.filter(s => !s.prohibited_violation).sort((a,b) => (b.weighted_total||0) - (a.weighted_total||0))
log(`Scored ${scored.length} ideas; ${viable.length} viable (not prohibited). Top: ${viable[0]?.name} @ ${viable[0]?.weighted_total}`)

// ---------- PHASE 4-6: CRAFT + ADVERSARIAL + CONVERGE (loop) ----------
const PROMPT_SCHEMA = {
  type: 'object',
  properties: {
    idea_name: { type: 'string' },
    idea_brief: { type: 'string', description: 'the clear brief: problem, who, what done looks like' },
    rubric_md: { type: 'string', description: 'the machine-gradable rubric.md content the agent grades itself against' },
    master_prompt: { type: 'string', description: 'THE single master prompt that drives the full agentic loop, spawning sub-agents with roles/goals/instructions, building, testing, deploying, self-correcting, looping until rubric passes' },
    subagent_roles: { type: 'array', items: { type: 'string' } },
    self_verification_plan: { type: 'string', description: 'how the model verifies done without a human: tests, responding URL curl, rubric grading' },
    file_written: { type: 'string' },
  },
  required: ['idea_name', 'master_prompt', 'rubric_md', 'self_verification_plan'],
}
const CRITIQUE_SCHEMA = {
  type: 'object',
  properties: {
    lens: { type: 'string' },
    approved: { type: 'boolean' },
    fatal_flaws: { type: 'array', items: { type: 'string' } },
    fixes_required: { type: 'array', items: { type: 'string' } },
    score_estimate: { type: 'number' },
  },
  required: ['lens', 'approved'],
}

let topIdea = viable[0] || scored.sort((a,b)=>(b.weighted_total||0)-(a.weighted_total||0))[0]
let solution = null
let feedback = ''
let round = 0
const MAX_ROUNDS = 3

while (round < MAX_ROUNDS) {
  round++
  phase('Craft')
  log(`Convergence round ${round}: crafting idea brief + rubric + master prompt for "${topIdea?.name}"`)
  solution = await agent(
    `${CONTEXT}\n\nFull research grounding:\n${groundingBlob}\n\nWINNING IDEA (top-scored): ${JSON.stringify(topIdea)}\nFull candidate idea details: ${JSON.stringify(candidateIdeas.find(i => i.name === topIdea.name) || candidateIdeas[0])}\n${feedback ? `\nADDRESS THIS CRITIC FEEDBACK FROM THE LAST ROUND:\n${feedback}\n` : ''}\nProduce the COMPLETE SOLUTION:\n1) idea_brief — the clear brief (problem, who, what "done" looks like).\n2) rubric_md — a machine-gradable rubric.md the agent grades ITSELF against (concrete, checkable items: tests pass, URL responds 200, features present).\n3) master_prompt — THE single master prompt to paste into Claude Code that drives the FULL agentic loop: decompose, spawn sub-agents (name their roles/goals/instructions), build, write+run tests, deploy to a live URL, CURL it to verify, self-correct on failure, and LOOP until rubric_md passes. Make it self-contained, specific to this idea, and self-verifying. Optimize for the 15% orchestration bar ("done" verifiable by the model; rerunnable tomorrow on a new problem).\n4) subagent_roles, self_verification_plan.\nWRITE the full solution to ${DIR}/SOLUTION.md (idea + brief + rubric + master prompt + verification). Return the object.`,
    { label: `craft:r${round}`, phase: 'Craft', schema: PROMPT_SCHEMA }
  )

  phase('Adversarial')
  const lenses = [
    { k: 'judge', p: 'You are an Anthropic judge. Will this idea+demo actually score top-3? Is the demo wow real and live-safe? Is it accidentally prohibited?' },
    { k: 'engineer', p: 'You are a skeptical senior engineer. Is this SOLO-shippable to a live URL in ~6h? Are the data APIs real and accessible today? Where does the master prompt break or loop forever?' },
    { k: 'orchestration', p: 'You are the orchestration grader. Is "done" truly verifiable by the MODEL with no human (real tests, responding URL, gradable rubric)? Could another team rerun this tomorrow on a new problem? Does the master prompt actually spawn sub-agents and self-correct, or is it hand-wavy?' },
  ]
  const critiques = (await parallel(lenses.map(l => () =>
    agent(
      `${CONTEXT}\n\nLENS: ${l.p}\n\nSOLUTION TO BREAK:\nIDEA: ${JSON.stringify(topIdea)}\nBRIEF: ${solution.idea_brief}\nRUBRIC:\n${solution.rubric_md}\nMASTER PROMPT:\n${solution.master_prompt}\nVERIFICATION: ${solution.self_verification_plan}\n\nTry hard to find FATAL flaws. Only approve if it would genuinely place top-3 and is fully self-verifying. List fatal_flaws and fixes_required.`,
      { label: `critic:${l.k}:r${round}`, phase: 'Adversarial', schema: CRITIQUE_SCHEMA }
    )
  ))).filter(Boolean)

  const approvals = critiques.filter(c => c.approved).length
  const allFlaws = critiques.flatMap(c => [...(c.fatal_flaws||[]), ...(c.fixes_required||[])]);
  log(`Round ${round}: ${approvals}/${critiques.length} critics approved. ${allFlaws.length} issues raised.`)

  if (approvals === critiques.length) {
    log(`CONVERGED on round ${round}: all critics approved "${topIdea?.name}".`)
    phase('Converge')
    break
  }
  feedback = allFlaws.map((f,i)=>`${i+1}. ${f}`).join('\n')
  // If the idea itself is fatally flawed by majority, try the next-best viable idea next round.
  const ideaFatal = critiques.filter(c => (c.fatal_flaws||[]).some(f => /prohibited|not feasible|won't score|idea is/i.test(f))).length >= 2
  if (ideaFatal && viable.length > 1) {
    const idx = viable.findIndex(v => v.name === topIdea.name)
    topIdea = viable[idx + 1] || topIdea
    log(`Idea judged fatally flawed; pivoting to next-best: "${topIdea?.name}"`)
  }
}

phase('Converge')
return {
  converged_idea: topIdea?.name,
  rounds_used: round,
  solution_doc: `${DIR}/SOLUTION.md`,
  research_docs: `${DIR}/`,
  idea_brief: solution?.idea_brief,
  subagent_roles: solution?.subagent_roles,
  self_verification_plan: solution?.self_verification_plan,
}

export const meta = {
  name: 'hackathon-idea-2-broad',
  description: 'Deep-research loop to converge on a SECOND hackathon idea + master orchestration prompt — broad/highest-EV steer (no nonprofit constraint)',
  phases: [
    { title: 'Sweep', detail: '10 parallel research agents, each writes a grounding doc' },
    { title: 'Synthesize', detail: 'merge research, generate candidate ideas' },
    { title: 'Score', detail: 'parallel judges score each idea vs rubric + prohibited list' },
    { title: 'Craft', detail: 'write the master agentic-loop prompt for the winning idea' },
    { title: 'Adversarial', detail: 'critics try to break the idea and the prompt' },
    { title: 'Converge', detail: 'revise and re-check until a critic approves' },
  ],
}

