  properties: {
    lane: { type: 'string' },
    file_written: { type: 'string', description: 'absolute path of the .md doc you wrote' },
    key_findings: { type: 'array', items: { type: 'string' }, description: '8-15 concrete, specific findings with sources' },
    implications_for_idea: { type: 'array', items: { type: 'string' } },
    implications_for_prompt: { type: 'array', items: { type: 'string' } },
    sources: { type: 'array', items: { type: 'string' } },
  },
  required: ['lane', 'file_written', 'key_findings'],
}

const LANES = [
  { key: 'prior-winners', title: 'Prior Anthropic/CV/Claude hackathon winning repos & patterns',
    task: `Mine GitHub and the web for projects that WON or placed in Anthropic / Cerebral Valley / Claude-Code hackathons and similar agentic-AI hackathons (2024-2026). For each: what it did, why it won, the demo hook, repo link. Extract the PATTERN behind winners across ALL domains (dev tools, agentic infra, B2B automation, creative tools, consumer). What kinds of ideas win agentic-AI hackathons judged on impact+demo+orchestration? Search GitHub topics, "cerebral valley hackathon winner", "claude hackathon project", Devpost, etc.` },
  { key: 'claude-build-day-repos', title: 'Claude Build Day / Claude Code dynamic-workflow showcases',
