  { key: 'deploy-fast', title: 'Fastest solo path to a live URL + tech stack',
    task: `Research the fastest solo stack to ship a LIVE URL in <6h that an agent can deploy then CURL to self-verify: Vercel/Next, Cloudflare Workers, Render, Railway, static + serverless, plus CLI/desktop distribution if the idea is a tool. Which targets an agent can drive end-to-end via CLI and health-check. Recommend ONE default optimized for agent-driven deploy + self-verification.` },
]

phase('Sweep')
log('Round 1: 10 parallel research agents (broad/highest-EV steer)')
const sweep = await parallel(LANES.map(lane => () =>
  agent(
    `${CONTEXT}\n\nYOU ARE RESEARCH LANE: "${lane.title}".\nTASK: ${lane.task}\n\nDo thorough live web research (WebSearch + mcp__turbowebfetch__fetch via ToolSearch). Be specific and cite URLs.\nThen WRITE your findings as a markdown doc to ${DIR}/01-${lane.key}.md (Write tool, absolute path). Structure: ## Findings (specific, sourced), ## Implications for the IDEA, ## Implications for the PROMPT, ## Sources.\nReturn the structured object.`,
    { label: `sweep:${lane.key}`, phase: 'Sweep', schema: FINDINGS_SCHEMA }
