log(`Sweep complete: ${sweep.length}/10 lanes returned`)

phase('Synthesize')
const groundingBlob = sweep.map(s =>
  `### ${s.lane}\nFINDINGS:\n- ${(s.key_findings||[]).join('\n- ')}\nIDEA-IMPLICATIONS:\n- ${(s.implications_for_idea||[]).join('\n- ')}\nPROMPT-IMPLICATIONS:\n- ${(s.implications_for_prompt||[]).join('\n- ')}`
).join('\n\n')

const IDEAS_SCHEMA = {
  type: 'object',
  properties: {
    ideas: { type: 'array', items: { type: 'object', properties: {
      name: { type: 'string' }, one_liner: { type: 'string' }, problem: { type: 'string' },
      who_benefits: { type: 'string' }, data_or_inputs_used: { type: 'string' },
      demo_wow_moment: { type: 'string' }, why_not_prohibited: { type: 'string' },
      feasible_solo_6h: { type: 'string' }, opus48_creative_use: { type: 'string' },
    }, required: ['name', 'one_liner', 'problem', 'demo_wow_moment', 'why_not_prohibited'] } },
  },
  required: ['ideas'],
}
const synth = await agent(
  `${CONTEXT}\n\nMerged research from 10 lanes:\n${groundingBlob}\n\nFirst, WRITE a synthesis grounding doc to ${DIR}/02-synthesis.md (cross-cutting insights, winning pattern, design constraints).\nThen generate 5 distinct, strong CANDIDATE IDEAS from the BROAD space (NOT nonprofit/civic, and DISTINCT from a benefits/eligibility navigator) that: (a) are NOT on the prohibited list (no dashboard-as-main-feature, no basic RAG), (b) are solo-shippable to a live URL in ~6h, (c) have a 30-second "wow" demo moment, (d) showcase creative Opus 4.8 + orchestration, (e) maximize the weighted rubric. Be concrete about exact inputs/data/APIs. Return the ideas object.`,
  { label: 'synthesize', phase: 'Synthesize', schema: IDEAS_SCHEMA }
)
const candidateIdeas = synth.ideas || []
log(`Generated ${candidateIdeas.length} candidate ideas`)

phase('Score')
const SCORE_SCHEMA = {
  type: 'object',
  properties: {
    name: { type: 'string' }, impact_35: { type: 'number' }, demo_35: { type: 'number' },
    opus48_15: { type: 'number' }, orchestration_15: { type: 'number' }, weighted_total: { type: 'number' },
    prohibited_violation: { type: 'boolean' }, prohibited_note: { type: 'string' },
    risks: { type: 'array', items: { type: 'string' } }, verdict: { type: 'string' },
  },
  required: ['name', 'weighted_total', 'prohibited_violation', 'verdict'],
}
const scored = (await parallel(candidateIdeas.map(idea => () =>
  agent(
    `${CONTEXT}\n\nAdversarially SCORE this candidate against the EXACT rubric as a harsh Anthropic judge.\nIDEA: ${JSON.stringify(idea)}\n\nScore impact /35, demo /35, opus48 /15, orchestration /15, sum to weighted_total /100. CRITICALLY check the prohibited list (esp. "dashboard as main feature", "basic RAG") — set prohibited_violation true if it resembles any banned category. List real risks. Verdict.`,
    { label: `score:${(idea.name||'idea').slice(0,20)}`, phase: 'Score', schema: SCORE_SCHEMA }
  )
))).filter(Boolean)
const viable = scored.filter(s => !s.prohibited_violation).sort((a,b) => (b.weighted_total||0) - (a.weighted_total||0))
log(`Scored ${scored.length}; ${viable.length} viable. Top: ${viable[0]?.name} @ ${viable[0]?.weighted_total}`)

const PROMPT_SCHEMA = {
  type: 'object',
  properties: {
    idea_name: { type: 'string' }, idea_brief: { type: 'string' }, rubric_md: { type: 'string' },
    master_prompt: { type: 'string' }, subagent_roles: { type: 'array', items: { type: 'string' } },
    self_verification_plan: { type: 'string' }, file_written: { type: 'string' },
  },
  required: ['idea_name', 'master_prompt', 'rubric_md', 'self_verification_plan'],
}
const CRITIQUE_SCHEMA = {
  type: 'object',
  properties: {
    lens: { type: 'string' }, approved: { type: 'boolean' },
    fatal_flaws: { type: 'array', items: { type: 'string' } },
    fixes_required: { type: 'array', items: { type: 'string' } }, score_estimate: { type: 'number' },
  },
  required: ['lens', 'approved'],
}

let topIdea = viable[0] || scored.sort((a,b)=>(b.weighted_total||0)-(a.weighted_total||0))[0]
let solution = null, feedback = '', round = 0
const MAX_ROUNDS = 3
while (round < MAX_ROUNDS) {
  round++
  phase('Craft')
  log(`Convergence round ${round}: crafting for "${topIdea?.name}"`)
  solution = await agent(
    `${CONTEXT}\n\nResearch grounding:\n${groundingBlob}\n\nWINNING IDEA: ${JSON.stringify(topIdea)}\nFull details: ${JSON.stringify(candidateIdeas.find(i => i.name === topIdea.name) || candidateIdeas[0])}\n${feedback ? `\nADDRESS THIS CRITIC FEEDBACK:\n${feedback}\n` : ''}\nProduce the COMPLETE SOLUTION:\n1) idea_brief (problem, who, what "done" looks like).\n2) rubric_md — machine-gradable rubric.md the agent grades ITSELF against (tests pass, URL responds 200, features present).\n3) master_prompt — THE single master prompt for Claude Code driving the FULL agentic loop: decompose, spawn roled sub-agents (goals/instructions), build, write+run tests, deploy to a live URL, CURL to verify, self-correct, LOOP until rubric passes. Self-contained, idea-specific, self-verifying. Optimize the 15% orchestration bar (model-verifiable done; rerunnable tomorrow).\n4) subagent_roles, self_verification_plan.\nWRITE the full solution to ${DIR}/SOLUTION.md. Return the object.`,
    { label: `craft:r${round}`, phase: 'Craft', schema: PROMPT_SCHEMA }
  )
  phase('Adversarial')
  const lenses = [
    { k: 'judge', p: 'You are an Anthropic judge. Will this idea+demo actually score top-3? Is the wow real and live-safe? Accidentally prohibited?' },
    { k: 'engineer', p: 'You are a skeptical senior engineer. Solo-shippable to a live URL in ~6h? Are the data/APIs real and accessible today? Where does the master prompt break or loop forever?' },
    { k: 'orchestration', p: 'You are the orchestration grader. Is "done" truly verifiable by the MODEL with no human (real tests, responding URL, gradable rubric)? Rerunnable tomorrow on a new problem? Does the prompt actually spawn sub-agents and self-correct, or is it hand-wavy?' },
  ]
  const critiques = (await parallel(lenses.map(l => () =>
    agent(
      `${CONTEXT}\n\nLENS: ${l.p}\n\nSOLUTION TO BREAK:\nIDEA: ${JSON.stringify(topIdea)}\nBRIEF: ${solution.idea_brief}\nRUBRIC:\n${solution.rubric_md}\nMASTER PROMPT:\n${solution.master_prompt}\nVERIFICATION: ${solution.self_verification_plan}\n\nFind FATAL flaws. Only approve if it would genuinely place top-3 and is fully self-verifying. List fatal_flaws and fixes_required.`,
      { label: `critic:${l.k}:r${round}`, phase: 'Adversarial', schema: CRITIQUE_SCHEMA }
    )
  ))).filter(Boolean)
  const approvals = critiques.filter(c => c.approved).length
  const allFlaws = critiques.flatMap(c => [...(c.fatal_flaws||[]), ...(c.fixes_required||[])])
  log(`Round ${round}: ${approvals}/${critiques.length} approved. ${allFlaws.length} issues.`)
  if (approvals === critiques.length) { log(`CONVERGED round ${round}: "${topIdea?.name}".`); phase('Converge'); break }
  feedback = allFlaws.map((f,i)=>`${i+1}. ${f}`).join('\n')
  const ideaFatal = critiques.filter(c => (c.fatal_flaws||[]).some(f => /prohibited|not feasible|won't score|idea is/i.test(f))).length >= 2
  if (ideaFatal && viable.length > 1) {
    const idx = viable.findIndex(v => v.name === topIdea.name)
    topIdea = viable[idx + 1] || topIdea
    log(`Idea fatally flawed; pivoting to next-best: "${topIdea?.name}"`)
  }
}
phase('Converge')
return {
  converged_idea: topIdea?.name, rounds_used: round,
  solution_doc: `${DIR}/SOLUTION.md`, research_docs: `${DIR}/`,
  idea_brief: solution?.idea_brief, subagent_roles: solution?.subagent_roles,
  self_verification_plan: solution?.self_verification_plan,
}

